import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../api/axios';
import { useAuth } from '../context/AuthContext';

const STATUS_COLOR = { Pending: '#f59e0b', Approved: '#10b981', Rejected: '#ef4444' };

export default function ManagerDashboard() {
  const { user, logout } = useAuth();
  const [expenses, setExpenses] = useState([]);
  const [comment, setComment] = useState({});

  useEffect(() => {
    api.get('/expenses').then((res) => setExpenses(res.data));
  }, []);

  const handleAction = async (id, action) => {
    try {
      await api.put(`/expenses/${id}/approve`, { action, comment: comment[id] || '' });
      const res = await api.get('/expenses');
      setExpenses(res.data);
    } catch (err) {
      alert(err.response?.data?.message || 'Action failed');
    }
  };

  const pending = expenses.filter((e) =>
    e.status === 'Pending' &&
    e.approvals.some((a) => a.approverId?._id === user?._id && a.status === 'Pending')
  );

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <h2>Pending Approvals</h2>
        <button style={styles.btnLogout} onClick={logout}>Logout</button>
      </header>
      <p>Welcome, {user?.name} ({user?.role})</p>
      {pending.length === 0 && <p>No pending approvals.</p>}
      {pending.map((e) => (
        <div key={e._id} style={styles.card}>
          <p><strong>Employee:</strong> {e.employee?.name}</p>
          <p><strong>Category:</strong> {e.category} | <strong>Amount:</strong> {e.amount} {e.currency}</p>
          <p><strong>Converted:</strong> {e.convertedAmount?.toFixed(2)} {e.convertedCurrency}</p>
          <p><strong>Date:</strong> {new Date(e.date).toLocaleDateString()}</p>
          <p><strong>Description:</strong> {e.description}</p>
          <textarea placeholder="Comment (optional)" style={styles.textarea}
            value={comment[e._id] || ''}
            onChange={(ev) => setComment({ ...comment, [e._id]: ev.target.value })} />
          <div>
            <button style={styles.btnApprove} onClick={() => handleAction(e._id, 'Approved')}>Approve</button>
            <button style={styles.btnReject} onClick={() => handleAction(e._id, 'Rejected')}>Reject</button>
            <Link to={`/expenses/${e._id}`} style={{ marginLeft: '0.5rem' }}>Details</Link>
          </div>
        </div>
      ))}
      <h3 style={{ marginTop: '2rem' }}>All Expenses</h3>
      <table style={styles.table}>
        <thead>
          <tr>{['Employee', 'Category', 'Amount', 'Status', 'Detail'].map((h) => <th key={h} style={styles.th}>{h}</th>)}</tr>
        </thead>
        <tbody>
          {expenses.map((e) => (
            <tr key={e._id}>
              <td style={styles.td}>{e.employee?.name}</td>
              <td style={styles.td}>{e.category}</td>
              <td style={styles.td}>{e.amount} {e.currency}</td>
              <td style={styles.td}><span style={{ color: STATUS_COLOR[e.status] }}>{e.status}</span></td>
              <td style={styles.td}><Link to={`/expenses/${e._id}`}>View</Link></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

const styles = {
  page: { maxWidth: '900px', margin: '2rem auto', padding: '0 1rem' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  card: { background: '#fff', border: '1px solid #e5e7eb', borderRadius: '8px', padding: '1rem', marginBottom: '1rem' },
  textarea: { display: 'block', width: '100%', padding: '0.5rem', marginBottom: '0.5rem', borderRadius: '4px', border: '1px solid #ccc', boxSizing: 'border-box' },
  btnApprove: { padding: '0.4rem 1rem', background: '#10b981', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer', marginRight: '0.5rem' },
  btnReject: { padding: '0.4rem 1rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  btnLogout: { padding: '0.5rem 1rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { background: '#f3f4f6', padding: '0.6rem', textAlign: 'left', borderBottom: '1px solid #e5e7eb' },
  td: { padding: '0.6rem', borderBottom: '1px solid #e5e7eb' },
};
